import { Link } from "react-router-dom";
import axios from 'axios';
import { useState } from "react";

const RegisterPage = () => {
  const [user, setUser] = useState({
    name:"",
    email:"",
    password:""
  })

  const handleChange =(e)=>{
    console.log(e.target.value)
    setUser({...user,[e.target.name]:e.target.value})
  }

    async function handleSubmit(e){
      e.preventDefault()
      console.log(user)
      try {
          await axios.post('/auth/register',user)
      } catch (error) {
        console.log(error.response.data.msg)
      }
    }
  return (
    <div>
      <h1 className="mx-auto m-4 w-28">Register PAGE</h1>
      <div>
        <form action="" className="flex justify-center"  onSubmit={handleSubmit}>
          <div className="flex flex-col w-96 ">
            <input type="text" placeholder="NAME" name="name"  value={user.name} onChange={handleChange}/>
            <input type="text" placeholder="EMAIL" name="email" value={user.email} onChange={handleChange}/>
            <input type="text" placeholder="PASSWORD" name="password" value={user.password} onChange={handleChange}/>
            <button className="">REGISTER</button>
            <div className="mt-5">
              Already A Member ?{" "}
              <Link to={"/login"} className="text-black font-bold">
                LOGIN
              </Link>
            </div>
          </div>
        </form>
      </div>
    </div>
  );
};

export default RegisterPage;
